from datetime import datetime, timedelta, timezone
from functools import wraps
from typing import Optional, Dict, Any

import jwt
from flask import Flask, request, jsonify, g

app = Flask(__name__)

app.config["JWT_SECRET_KEY"] = "change-this-secret-key"
app.config["JWT_ALGORITHM"] = "HS256"
app.config["JWT_ACCESS_TOKEN_EXPIRES"] = timedelta(hours=1)

USERS = {
    "admin": {
        "password": "password123",
        "id": 1,
        "role": "admin",
    }
}


def create_access_token(identity: str, additional_claims: Optional[Dict[str, Any]] = None) -> str:
    now = datetime.now(timezone.utc)
    payload = {
        "sub": identity,
        "iat": int(now.timestamp()),
        "exp": int((now + app.config["JWT_ACCESS_TOKEN_EXPIRES"]).timestamp()),
    }
    if additional_claims:
        payload.update(additional_claims)
    return jwt.encode(payload, app.config["JWT_SECRET_KEY"], algorithm=app.config["JWT_ALGORITHM"])


def decode_access_token(token: str) -> Dict[str, Any]:
    return jwt.decode(
        token,
        app.config["JWT_SECRET_KEY"],
        algorithms=[app.config["JWT_ALGORITHM"]],
    )


def jwt_required(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            return jsonify({"msg": "Missing or invalid Authorization header"}), 401

        token = auth_header.split(" ", 1)[1].strip()
        if not token:
            return jsonify({"msg": "Missing token"}), 401

        try:
            claims = decode_access_token(token)
        except jwt.ExpiredSignatureError:
            return jsonify({"msg": "Token has expired"}), 401
        except jwt.InvalidTokenError:
            return jsonify({"msg": "Invalid token"}), 401

        g.jwt_claims = claims
        g.current_user = claims.get("sub")
        return fn(*args, **kwargs)

    return wrapper


@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or {}
    username = data.get("username")
    password = data.get("password")

    user = USERS.get(username)
    if not user or user["password"] != password:
        return jsonify({"msg": "Bad username or password"}), 401

    token = create_access_token(
        identity=username,
        additional_claims={"user_id": user["id"], "role": user["role"]},
    )
    return jsonify(access_token=token)


